#!/usr/bin/perl
use strict;
use warnings;
use File::Spec;
use File::Basename;
use Cwd 'abs_path';

my $CONFIG_DIR = $ENV{PLUGIN_CONFIG_DIR} || './plugins';
my %loaded_plugins;
my %plugin_hooks;

sub load_plugin_config {
    my ($config_file) = @_;
    
    open my $fh, '<', $config_file or die "Cannot open config file $config_file: $!";
    my $content = do { local $/; <$fh> };
    close $fh;
    
    return $content;
}

sub register_plugin {
    my ($name, $code, $metadata) = @_;
    
    $loaded_plugins{$name} = {
        code => $code,
        metadata => $metadata || {},
        loaded_at => time(),
    };
    
    print "Plugin '$name' registered successfully\n";
}

sub execute_plugin {
    my ($plugin_name, @args) = @_;
    
    unless (exists $loaded_plugins{$plugin_name}) {
        die "Plugin '$plugin_name' not found\n";
    }
    
    my $plugin_code = $loaded_plugins{$plugin_name}->{code};
    my $result;
    
    eval {
        $result = eval $plugin_code;
        die $@ if $@;
    };
    
    if ($@) {
        warn "Error executing plugin '$plugin_name': $@\n";
        return undef;
    }
    
    return $result;
}

sub execute_plugin_with_context {
    my ($plugin_name, $context, @args) = @_;
    
    unless (exists $loaded_plugins{$plugin_name}) {
        die "Plugin '$plugin_name' not found\n";
    }
    
    my $plugin_code = $loaded_plugins{$plugin_name}->{code};
    my $result;
    
    local our %CONTEXT = %$context if ref $context eq 'HASH';
    local our @ARGS = @args;
    
    eval {
        $result = eval $plugin_code;
        die $@ if $@;
    };
    
    if ($@) {
        warn "Error executing plugin '$plugin_name': $@\n";
