}

sub register_hook {
    my ($hook_name, $plugin_name, $code) = @_;
    
    push @{$plugin_hooks{$hook_name}}, {
        plugin => $plugin_name,
        code => $code,
    };
    
    print "Hook '$hook_name' registered for plugin '$plugin_name'\n";
}

sub execute_hook {
    my ($hook_name, @args) = @_;
    
    return unless exists $plugin_hooks{$hook_name};
    
    my @results;
    
    foreach my $hook (@{$plugin_hooks{$hook_name}}) {
        my $code = $hook->{code};
        my $plugin = $hook->{plugin};
        
        eval {
            my $result = eval $code;
            die $@ if $@;
            push @results, $result;
        };
        
        if ($@) {
            warn "Error executing hook '$hook_name' from plugin '$plugin': $@\n";
        }
    }
    
    return @results;
}

sub load_all_plugins {
    my ($config_dir) = @_;
    $config_dir ||= $CONFIG_DIR;
    
    unless (-d $config_dir) {
        warn "Plugin directory '$config_dir' does not exist\n";
        return;
    }
    
    opendir my $dh, $config_dir or die "Cannot open directory $config_dir: $!";
    my @config_files = grep { /\.pl$/ && -f "$config_dir/$_" } readdir($dh);
    closedir $dh;
    
    foreach my $file (@config_files) {
        my $full_path = File::Spec->catfile($config_dir, $file);
        my $plugin_name = basename($file, '.pl');
        
        print "Loading plugin from: $full_path\n";
        
        my $plugin_code = load_plugin_config($full_path);
        
        register_plugin($plugin_name, $plugin_code, {
            file => $full_path,
            name => $plugin_name,
        });
    }
    
    print "Loaded " . scalar(keys %loaded_plugins) . " plugins\n";
}

sub execute_plugin_function {
    my ($plugin_name, $function_name, @args) = @_;
    
    unless (exists $loaded_plugins{$plugin_name}) {
        die "Plugin '$plugin_name' not found\n";
    }
    
    my $plugin_code = $loaded_plugins{$plugin_name}->{code};
    my $result;
    
    local our @PLUGIN_ARGS = @args;
    
    my $wrapper_code = qq{
        $plugin_code;
        $function_name(\@PLUGIN_ARGS);
    };
    
    eval {
        $result = eval $wrapper_code;
        die $@ if $@;
    };
    
    if ($@) {
        warn "Error executing function '$function_name' in plugin '$plugin_name': $@\n";
        return undef;
    }
    
    return $result;
}

sub list_plugins {
    print "\nLoaded Plugins:\n";
    print "-" x 60 . "\n";
    
    foreach my $name (sort keys %loaded_plugins) {
        my $plugin = $loaded_plugins{$name};
        print "Plugin: $name\n";
        print "  File: " . ($plugin->{metadata}->{file} || 'N/A') . "\n";
        print "  Loaded: " . localtime($plugin->{loaded_at}) . "\n";
        print "\n";
    }
}

sub reload_plugin {
    my ($plugin_name) = @_;
    
    unless (exists $loaded_plugins{$plugin_name}) {
        die "Plugin '$plugin_name' not found\n";
    }
    
    my $file = $loaded_plugins{$plugin_name}->{metadata}->{file};
    
    unless ($file && -f $file) {
        die "Cannot reload plugin '$plugin_name': source file not found\n";
    }
    
    print "Reloading plugin '$plugin_name' from $file\n";
    
    my $plugin_code = load_plugin_config($file);
    
    register_plugin($plugin_name, $plugin_code, {
        file => $file,
        name => $plugin_name,
    });
}

